INSERT INTO `v1_74b805e396769085a154cc715bfb6bf4efa721aeff718d76e747674fb43630eb` VALUES (1, 0, 944, 19440033, 10, 11, 1, 0, "なんだ、ユカリだったかにゃ。\n何ってもちろん商売にゃ！", 0, 107911);
INSERT INTO `v1_74b805e396769085a154cc715bfb6bf4efa721aeff718d76e747674fb43630eb` VALUES ("", "", 944, 19440034, "", 91, "", "", "", "", 0);
