INSERT INTO `v1_74b805e396769085a154cc715bfb6bf4efa721aeff718d76e747674fb43630eb` VALUES (1, 0, 944, 19440038, 10, 11, 1, 0, "こんなに人がいっぱいいる商機、\n見逃すわけにはいかないにゃ！", 0, 107911);
INSERT INTO `v1_74b805e396769085a154cc715bfb6bf4efa721aeff718d76e747674fb43630eb` VALUES ("", "", 944, 19440039, "", 91, "", "", "", "", 0);
