INSERT INTO `v1_74b805e396769085a154cc715bfb6bf4efa721aeff718d76e747674fb43630eb` VALUES ("45_yui_shy_loop", 0.1, 945, 19450030, 0, 3, "", 1, "45_yui_shy_in", 0.1, 122611);
