INSERT INTO `v1_74b805e396769085a154cc715bfb6bf4efa721aeff718d76e747674fb43630eb` VALUES (0, "", 945, 19450032, "", 21, "", "", "vo_fpc_30504", "", "vo_fpc");
INSERT INTO `v1_74b805e396769085a154cc715bfb6bf4efa721aeff718d76e747674fb43630eb` VALUES (1, 0, 945, 19450033, 5, 11, 1, 0, "…うん、やっちゃった…\nおっきなハートマーク…\nやっぱりこれは無しで！\nマコトちゃん食べてくれる！？", 0, 122611);
INSERT INTO `v1_74b805e396769085a154cc715bfb6bf4efa721aeff718d76e747674fb43630eb` VALUES ("", "", 945, 19450034, "", 91, "", "", "", "", 0);
INSERT INTO `v1_74b805e396769085a154cc715bfb6bf4efa721aeff718d76e747674fb43630eb` VALUES ("", "", 945, 19450035, 1, 3, "", "", "45_makoto_idle", 0.1, 110411);
INSERT INTO `v1_74b805e396769085a154cc715bfb6bf4efa721aeff718d76e747674fb43630eb` VALUES (0, "", 945, 19450036, "", 21, "", "", "vo_fpc_30505", "", "vo_fpc");
